// ═══════════════════════════════════════════════════════════════
// STRUCTURATION DES DONNÉES BC PAR DESTINATAIRE ET NIVEAU D'ALERTE
//
// Règles métier :
// ─────────────────────────────────────────────────────────────
// ALERTE_JURIDIQUE   → Destinataire : BAALLAH
// ALERTE_CREATEUR    → Destinataire : Créateur du BC
// ALERTE_RESPONSABLE → Destinataires : Responsable Achat + Responsable Compta
//                      (deux notifications séparées, chacune avec ses BCs)
// OK                 → Ignoré (pas de notification)
//
// Regroupement : plusieurs BCs d'un même destinataire = 1 seule notification
// ═══════════════════════════════════════════════════════════════

const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📦 STRUCTURATION DES NOTIFICATIONS - BON DE COMMANDE');
console.log('═══════════════════════════════════════════════════');
console.log(`BCs reçus: ${items.length}`);

// ── Buckets de regroupement par clé unique destinataire ──────────
const notifications = {};

// ── Helpers ──────────────────────────────────────────────────────
function toInt(val) {
  const n = parseInt(val, 10);
  return isNaN(n) ? 0 : n;
}

function buildBcEntry(data) {
  return {
    numero_bc:                data.numero_bc,
    date_creation:            data.date_creation,
    code_fournisseur:         data.code_fournisseur,
    code_fournisseur_sage100: data.code_fournisseur_sage100,
    raison_fournisseur:       data.raison_fournisseur,
    comptable:                data.comptable,
    jours_ecoules:            toInt(data.jours_ecoules),
    jours_restants_blocage:   toInt(data.jours_restants_blocage),
    jours_restants_juridique: toInt(data.jours_restants_juridique),
    jours_restants_createur:  toInt(data.jours_restants_createur),
    jours_restants_responsable: toInt(data.jours_restants_responsable),
    niveau_alerte:            data.niveau_alerte,
    param_delai_max:          toInt(data.param_delai_max),
    param_delai_juridique:    toInt(data.param_delai_juridique),
    param_delai_createur:     toInt(data.param_delai_createur),
    param_delai_responsable:  toInt(data.param_delai_responsable),
    // Créateur du BC (pour contexte dans tous les niveaux)
    createur: {
      code:  data.code_x3_createur,
      nom:   data.nom_createur,
      prenom: data.prenom_createur,
      nom_complet: data.nom_complet_createur,
      email: data.email_createur,
      poste: data.poste_createur
    }
  };
}

function upsertNotification(cle, destinataire, typeDestinataire, niveauAlerte, bc) {
  if (!notifications[cle]) {
    notifications[cle] = {
      destinataire_principal: destinataire,
      type_destinataire:      typeDestinataire,
      niveau_alerte:          niveauAlerte,
      bcs: []
    };
  }
  notifications[cle].bcs.push(bc);
}

// ── Traitement de chaque BC ───────────────────────────────────────
items.forEach(item => {
  const data = item.json;
  const niveau = data.niveau_alerte;

  // ── BCs "OK" : aucune notification ───────────────────────────
  if (niveau === 'OK') {
    console.log(`✅ BC ${data.numero_bc} ignoré (statut OK)`);
    return;
  }

  const bc = buildBcEntry(data);

  // ── ALERTE_JURIDIQUE → BAALLAH ────────────────────────────────
  if (niveau === 'ALERTE_JURIDIQUE') {
    const cle = `BAALLAH_${data.code_x3_baallah}`;
    const destinataire = {
      code:      data.code_x3_baallah,
      nom:       data.nom_baallah,
      prenom:    data.prenom_baallah,
      email:     data.email_baallah   || null,
      telephone: data.tele_baallah    || null
    };
    upsertNotification(cle, destinataire, 'BAALLAH', niveau, bc);
    return;
  }

  // ── ALERTE_CREATEUR → Créateur du BC ─────────────────────────
  if (niveau === 'ALERTE_CREATEUR') {
    const cle = `CREATEUR_${data.code_x3_createur}`;
    const destinataire = {
      code:      data.code_x3_createur,
      nom:       data.nom_createur,
      prenom:    data.prenom_createur,
      nom_complet: data.nom_complet_createur,
      email:     data.email_createur  || null,
      telephone: null,
      poste:     data.poste_createur
    };
    upsertNotification(cle, destinataire, 'CREATEUR', niveau, bc);
    return;
  }

  // ── ALERTE_RESPONSABLE → Responsable Achat + Responsable Compta ─
  if (niveau === 'ALERTE_RESPONSABLE') {

    // 1. Responsable Achat
    const cleAchat = `RESPO_ACHAT_${data.code_x3_respo_achat}`;
    const destiAchat = {
      code:      data.code_x3_respo_achat,
      nom:       data.nom_respo_achat,
      prenom:    data.prenom_respo_achat,
      email:     data.email_respo_achat   || null,
      telephone: data.tele_respo_achat    || null,
      role:      'RESPONSABLE_ACHAT'
    };
    upsertNotification(cleAchat, destiAchat, 'RESPONSABLE_ACHAT', niveau, bc);

    // 2. Responsable Compta
    const cleCompta = `RESPO_COMPTA_${data.code_x3_respo_compta}`;
    const destiCompta = {
      code:      data.code_x3_respo_compta,
      nom:       data.nom_respo_compta,
      prenom:    data.prenom_respo_compta,
      email:     data.email_respo_compta  || null,
      telephone: data.tele_respo_comptat  || null,
      role:      'RESPONSABLE_COMPTA'
    };
    upsertNotification(cleCompta, destiCompta, 'RESPONSABLE_COMPTA', niveau, bc);
    return;
  }

  // ── Niveau inconnu ────────────────────────────────────────────
  console.log(`⚠️  BC ${data.numero_bc} ignoré (niveau inconnu: ${niveau})`);
});

// ── Finalisation : enrichissement statistiques ───────────────────
const resultats = Object.entries(notifications).map(([cle, notif]) => {
  const totalBcs   = notif.bcs.length;

  // Jours restants avant blocage : le minimum (= le plus urgent)
  const joursRestantsMin = Math.min(...notif.bcs.map(b => b.jours_restants_blocage));
  const joursRestantsMax = Math.max(...notif.bcs.map(b => b.jours_restants_blocage));

  // Jours restants spécifiques selon le type de destinataire
  let joursRestantsSpecifiques = null;
  if (notif.type_destinataire === 'BAALLAH') {
    joursRestantsSpecifiques = Math.min(...notif.bcs.map(b => b.jours_restants_juridique));
  } else if (notif.type_destinataire === 'CREATEUR') {
    joursRestantsSpecifiques = Math.min(...notif.bcs.map(b => b.jours_restants_createur));
  } else if (['RESPONSABLE_ACHAT', 'RESPONSABLE_COMPTA'].includes(notif.type_destinataire)) {
    joursRestantsSpecifiques = Math.min(...notif.bcs.map(b => b.jours_restants_responsable));
  }

  // Niveau de priorité visuel
  let priorite;
  if (joursRestantsSpecifiques < 0)      priorite = 'CRITIQUE';
  else if (joursRestantsSpecifiques === 0) priorite = 'URGENT';
  else if (joursRestantsSpecifiques <= 2)  priorite = 'ELEVE';
  else                                     priorite = 'NORMAL';

  return {
    // ── Identifiant interne du groupe ──────────────────────────
    cle_notification: cle,

    // ── Destinataire ───────────────────────────────────────────
    destinataire_principal: notif.destinataire_principal,
    type_destinataire:      notif.type_destinataire,
    niveau_alerte:          notif.niveau_alerte,

    // ── Canaux d'envoi disponibles ─────────────────────────────
    meta: {
      date_traitement:       new Date().toISOString(),
      peut_envoyer_email:    !!(notif.destinataire_principal.email &&
                                notif.destinataire_principal.email.trim() !== '' &&
                                notif.destinataire_principal.email.trim() !== 'A'),
      peut_envoyer_sms:      !!notif.destinataire_principal.telephone
    },

    // ── Statistiques du groupe ─────────────────────────────────
    statistiques: {
      total_bcs:                     totalBcs,
      jours_restants_blocage_min:    joursRestantsMin,
      jours_restants_blocage_max:    joursRestantsMax,
      jours_restants_specifiques_min: joursRestantsSpecifiques,
      priorite
    },

    // ── Liste des BCs concernés ────────────────────────────────
    bcs: notif.bcs
  };
});

// ── Tri par priorité décroissante (CRITIQUE en premier) ──────────
const ordrePriorite = { CRITIQUE: 0, URGENT: 1, ELEVE: 2, NORMAL: 3 };
resultats.sort((a, b) =>
  (ordrePriorite[a.statistiques.priorite] ?? 9) -
  (ordrePriorite[b.statistiques.priorite] ?? 9)
);

// ── Logs de synthèse ─────────────────────────────────────────────
const byType = {};
resultats.forEach(r => {
  byType[r.type_destinataire] = (byType[r.type_destinataire] || 0) + 1;
});

console.log(`\n✅ Notifications structurées : ${resultats.length}`);
console.log('Par type :');
Object.entries(byType).forEach(([type, count]) => {
  console.log(`  - ${type.padEnd(20)} : ${count} notification(s)`);
});
console.log('\nDétails :');
resultats.forEach(r => {
  const d = r.destinataire_principal;
  const nom = d.nom_complet || `${d.prenom || ''} ${d.nom || ''}`.trim();
  console.log(
    `  [${r.statistiques.priorite.padEnd(8)}] ${r.type_destinataire.padEnd(20)} ` +
    `| ${nom.padEnd(30)} | ${r.statistiques.total_bcs} BC(s) ` +
    `| jours restants spéc.: ${r.statistiques.jours_restants_specifiques_min}`
  );
});
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

// Diagnostic sur tous les items - voir le format exact de XDATE_0
return $input.all().map(item => {
  const date = item.json.XDATE_0;
  return {
    json: {
