// ── HELPERS ───────────────────────────────────────────────────────
function getLangue(data) {
  return (data.meta && data.meta.langue) || 'FRA';
}

function getT(langue) {
  return TEMPLATES[langue] || TEMPLATES.FRA;
}

function formaterDate(dateStr, langue) {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return date.toLocaleDateString(locale, { year: 'numeric', month: '2-digit', day: '2-digit' });
  } catch(e) { return dateStr; }
}

function getEmojiBlocage(joursRestants) {
  if (joursRestants <= 1)  return '🔴';
  if (joursRestants <= 4)  return '🟠';
  if (joursRestants <= 7)  return '🟡';
  if (joursRestants <= 10) return '🔵';
  return '🟢';
}

function emailValide(email) {
  if (!email) return false;
  const e = email.trim();
  return e !== '' && e !== 'A' && e.includes('@');
}

// ── GÉNÉRATION DU CORPS EMAIL ─────────────────────────────────────
function genererEmail(data) {
  const langue     = getLangue(data);
  const T          = getT(langue);
  const type       = data.type_destinataire;
  const dest       = data.destinataire_principal;
  const stats      = data.statistiques;
  const bcs        = data.bcs;
  const prioLabel  = T.priorite[stats.priorite] || stats.priorite;

  // ── Sujet ────────────────────────────────────────────────────
  const sujet = `${T.sujet_email[type] || T.sujet_email.CREATEUR} — ${stats.total_bcs} BC(s)`;

  // ── Corps ────────────────────────────────────────────────────
  let corps = '';

  corps += `${T.salutation} ${dest.prenom || ''} ${dest.nom || ''},\n\n`;
  corps += `${T.introduction[type]}\n\n`;

  // Bloc récapitulatif
  corps += `═══════════════════════════════════════════════════════\n`;
  corps += `📊 ${T.section_stats}\n`;
  corps += `═══════════════════════════════════════════════════════\n\n`;
  corps += `${prioLabel}\n`;
  corps += `${T.total} : ${stats.total_bcs}\n`;
  corps += `${T.blocage_min} : ${stats.jours_restants_blocage_min} ${T.jours}\n`;

  corps += `\n`;

  // Liste des BCs
  corps += `═══════════════════════════════════════════════════════\n`;
  corps += `📋 ${T.section_bcs}\n`;
  corps += `═══════════════════════════════════════════════════════\n\n`;

  bcs.forEach((bc, idx) => {
    const emoji = getEmojiBlocage(bc.jours_restants_blocage);
    corps += `${idx + 1}. ${emoji} ${bc.numero_bc}\n`;
    corps += `   📅 ${T.date_creation}   : ${formaterDate(bc.date_creation, langue)}\n`;
    corps += `   🏭 ${T.fournisseur}      : ${bc.raison_fournisseur || 'N/A'} (${bc.code_fournisseur || ''})\n`;
    corps += `   🧾 ${T.comptable}        : ${bc.comptable || 'N/A'}\n`;

    // Créateur affiché pour BAALLAH et RESPONSABLE (pas pour CREATEUR, c'est lui-même)
    if (type !== 'CREATEUR') {
      const cr = bc.createur;
      corps += `   👤 ${T.createur}         : ${cr ? (cr.nom_complet || `${cr.prenom} ${cr.nom}`) : 'N/A'}\n`;
    }

    corps += `   ⏱️  ${T.jours_ecoules}   : ${bc.jours_ecoules} ${T.jours}\n`;
    corps += `   ⏰ ${T.jours_blocage}     : ${bc.jours_restants_blocage} ${T.jours}\n`;

    if (bc.jours_restants_blocage <= 2) {
      corps += `   ${T.critique}\n`;
    }
    corps += `\n`;
  });

  // Instruction finale
  corps += `═══════════════════════════════════════════════════════\n`;
  if (stats.priorite === 'CRITIQUE' || stats.priorite === 'URGENT') {
    corps += `🚨 ${T.action_requise} : ${T.urgent}\n`;
  }
  corps += `📌 ${T.instruction[type]}\n`;
  corps += `═══════════════════════════════════════════════════════\n\n`;

  // Cordialement
  corps += `${T.cordialement},\n\n`;
  corps += `${T.signature}\n\n`;
  corps += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  corps += `🤖 ${T.message_auto} — ${formaterDate(new Date().toISOString(), langue)}\n`;
  corps += `${T.ne_pas_repondre}\n`;

  return { sujet, corps };
}

// ── GÉNÉRATION DU SMS ─────────────────────────────────────────────
function genererSMS(data) {
  const langue  = getLangue(data);
  const T       = getT(langue);
  const type    = data.type_destinataire;
  const stats   = data.statistiques;

  const fnSms = T.sms[type];
  if (!fnSms) return null;

  return fnSms(stats.total_bcs, stats.jours_restants_blocage_min);
}

// ── TRAITEMENT PRINCIPAL ──────────────────────────────────────────
const results = [];

console.log('\n═══════════════════════════════════════════════════');
console.log('📧 GÉNÉRATION DES MESSAGES - BONS DE COMMANDE');
console.log('═══════════════════════════════════════════════════');

inputData.forEach(item => {
  const data = item.json;
  const type = data.type_destinataire;
  const dest = data.destinataire_principal;

  // ── Vérification des canaux disponibles ────────────────────
  const peutEmail = data.meta.peut_envoyer_email && emailValide(dest.email);
  const peutSMS   = data.meta.peut_envoyer_sms   && !!dest.telephone;

  // ── CREATEUR sans email valide → log + skip ─────────────────
  if (type === 'CREATEUR' && !peutEmail) {
    console.log(`⚠️  CREATEUR ${dest.nom_complet || dest.nom} — email invalide (${dest.email}), notification ignorée`);
    results.push({
      json: {
        ...data,
        messages:         null,
        type_envoi:       'IGNORE',
        raison_ignore:    'email_invalide',
        destinataire_final: dest,
        meta: {
          ...data.meta,
          date_generation: new Date().toISOString(),
          peut_envoyer_email: false,
          peut_envoyer_sms:   false
        }
      }
    });
    return;
  }

  // ── Génération email & SMS ──────────────────────────────────
  const email = peutEmail ? genererEmail(data) : null;
  const sms   = peutSMS   ? genererSMS(data)   : null;

  results.push({
    json: {
      ...data,
      messages: {
        email: email ? { sujet: email.sujet, corps: email.corps } : null,
        sms:   sms   ? { texte: sms }                              : null
      },
      type_envoi:        'PRINCIPAL',
      destinataire_final: dest,
      meta: {
        ...data.meta,
        langue_utilisee:   getLangue(data),
        date_generation:   new Date().toISOString(),
        canaux_actifs: {
          email: peutEmail,
          sms:   peutSMS
        }
      }
    }
  });

  console.log(
    `  ✅ [${data.statistiques.priorite.padEnd(8)}] ${type.padEnd(20)}` +
    ` | ${(dest.nom_complet || `${dest.prenom} ${dest.nom}`).trim().padEnd(28)}` +
    ` | ${data.statistiques.total_bcs} BC(s)` +
    ` | email:${peutEmail ? '✔' : '✘'} sms:${peutSMS ? '✔' : '✘'}`
  );
});

// ── Synthèse logs ─────────────────────────────────────────────────
const envoyés  = results.filter(r => r.json.type_envoi === 'PRINCIPAL');
const ignorés  = results.filter(r => r.json.type_envoi === 'IGNORE');
const avecEmail = envoyés.filter(r => r.json.meta.canaux_actifs?.email);
const avecSMS   = envoyés.filter(r => r.json.meta.canaux_actifs?.sms);

console.log(`\n✅ Résumé :`);
console.log(`   Messages générés   : ${envoyés.length}`);
console.log(`   Avec email         : ${avecEmail.length}`);
console.log(`   Avec SMS           : ${avecSMS.length}`);
console.log(`   Ignorés (no email) : ${ignorés.length}`);
console.log('═══════════════════════════════════════════════════\n');

return results;
